// Build image prompt for Gemini (Nano Banana) - includes headline and footer so Gemini renders text.
const inputItem = $input.item.json;
let content = inputItem.choices?.[0]?.message?.content;
if (typeof content === 'string') {
  try { content = JSON.parse(content); } catch (e) { throw new Error('AI Writer content is not valid JSON: ' + e.message); }
}
const v1 = content.variation1Structured;
if (!v1 || !v1.headline || !v1.centralIcon || !Array.isArray(v1.orbitingIcons)) {
  throw new Error('Missing variation1Structured (headline, centralIcon, orbitingIcons). Got: ' + JSON.stringify(v1));
}
const icons = v1.orbitingIcons.slice(0, 6).join(', ');
const headline = String(v1.headline).trim();
const variation1Prompt = `Vertical 4:5 minimalist infographic. Top: "${headline}" in Montserrat Bold font and soft gradient only. Middle: one circular diagram with a single ${v1.centralIcon} icon in the center and five or six small icons around it: ${icons}. Icons only, no text in or under the diagram. Bottom: one dark grey bar only, flowos.tech in Raleway font. Background: soft teal and warm beige. Clean, simple, illustration only.`;
return { json: { variation1Prompt } };

// Format image URL for Prepare Content: supports Gemini (images[0].url) or overlay (url) response.
const inputItem = $input.item.json;
const url = inputItem.images?.[0]?.url || inputItem.url || inputItem.data?.url;
if (!url) throw new Error('No image URL in response. Check FAL Gemini or overlay response.');
return { json: { images: [{ url }] } };

// Prepare single generated image and content for posting
const inputItem = $input.item.json;
const aiContent = $('AI Writer - Content Generator').item.json.choices[0].message.content;
const pillarData = $('Content Pillar Rotation').item.json;
const imageUrl = inputItem.images?.[0]?.url || null;
if (!imageUrl) throw new Error('No image URL from overlay or FAL.');
return {
  json: {
    imageVariation1: imageUrl,
    title: aiContent.title,
    captions: aiContent.captions,
    pillar: pillarData.pillar,
    highlightedFeature: pillarData.highlightedFeature,
    generatedAt: new Date().toISOString(),
    previewData: {
      title: aiContent.title,
      pillar: pillarData.pillar,
      feature: pillarData.highlightedFeature,
      twitterPreview: aiContent.captions.twitter,
      instagramPreview: (aiContent.captions.instagram || '').substring(0, 200) + '...'
    }
  }
};

