// Extract base64 data from data URL for the selected image variation
// AUTO-POST MODE: Uses variation 1 by default (no approval needed)

// Get data from Prepare Content for Approval node
const preparedData = $('Prepare Content for Approval').item.json;

// Default to variation 1 (can be changed to 2 if preferred)
const selectedVariation = 1;
let dataUrl = selectedVariation === 1 ? preparedData.imageVariation1 : preparedData.imageVariation2;

if (!dataUrl) {
  throw new Error('No image data found. Check that image generation succeeded.');
}

// Check if it's a data URL (base64)
if (dataUrl && dataUrl.startsWith('data:')) {
  const matches = dataUrl.match(/^data:([^;]+);base64,(.+)$/);

  if (matches) {
    const mimeType = matches[1];
    const base64Data = matches[2];
    const imageBuffer = Buffer.from(base64Data, 'base64');
    const extension = mimeType.split('/')[1] || 'png';

    return {
      json: {
        url: dataUrl,
        mimeType: mimeType,
        fileName: `flowos-infographic-${Date.now()}.${extension}`,
        title: preparedData.title,
        captions: preparedData.captions,
        pillar: preparedData.pillar,
        selectedVariation: selectedVariation
      },
      binary: {
        data: {
          data: imageBuffer,
          mimeType: mimeType,
          fileName: `flowos-infographic-${Date.now()}.${extension}`
        }
      }
    };
  }
}

// If it's already a URL (not base64), just pass it through
return {
  json: {
    url: dataUrl,
    title: preparedData.title,
    captions: preparedData.captions,
    pillar: preparedData.pillar,
    selectedVariation: selectedVariation
  },
  binary: {}
};

// Get the image URL from FAL.ai and pass it through
// FAL.ai should return hosted URLs like https://fal.media/files/...

const inputData = $input.item.json;
const preparedData = $('Prepare Content for Approval').item.json;

// The URL should come from the previous node
let imageUrl = inputData.url;

// Debug: Log what we received to help troubleshoot
if (!imageUrl) {
  throw new Error('No image URL found in input. Input data: ' + JSON.stringify(Object.keys(inputData)));
}

// Check if it's a real URL or base64
const isBase64 = imageUrl.startsWith('data:');
const isHostedUrl = imageUrl.startsWith('http');

if (isBase64) {
  // FAL.ai returned base64 instead of a hosted URL
  // This is unexpected - throw an error with details so we can investigate
  throw new Error('FAL.ai returned base64 data instead of a hosted URL. First 100 chars: ' + imageUrl.substring(0, 100));
}

if (!isHostedUrl) {
  throw new Error('Unexpected URL format: ' + imageUrl.substring(0, 100));
}

// If we get here, we have a valid hosted URL from FAL.ai
return {
  json: {
    url: imageUrl,
    title: inputData.title || preparedData.title,
    captions: inputData.captions || preparedData.captions,
    pillar: inputData.pillar || preparedData.pillar,
    highlightedFeature: inputData.highlightedFeature || preparedData.highlightedFeature
  }
};

// Cost per run: estimate from FAL + OpenAI + Perplexity (token counts not always in output)
const item = $input.item.json;
const FAL_IMAGE_USD = 0.039;
const OPENAI_ESTIMATE_USD = 0.02;
const PERPLEXITY_ESTIMATE_USD = 0.02;
const totalUsd = FAL_IMAGE_USD + OPENAI_ESTIMATE_USD + PERPLEXITY_ESTIMATE_USD;
return {
  json: {
    ...item,
    runCost: {
      estimatedTotalUsd: Math.round(totalUsd * 100) / 100,
      falImageUsd: FAL_IMAGE_USD,
      openaiEstimateUsd: OPENAI_ESTIMATE_USD,
      perplexityEstimateUsd: PERPLEXITY_ESTIMATE_USD
    }
  }
};

